var UserConnection = Get<UserConnection>("UserConnection");
bool certificateCelcom = Get<bool>("CertificateCelcom");
string transactionNumber = Get<string>("TransactionNumber");
Guid recordId = Get<Guid>("RecordId");

try {
	var service = new OverrideDeviceService(UserConnection, certificateCelcom);
	
    service.SetParam(transactionNumber, recordId)
            .Request().GetAwaiter().GetResult();
    
    Set("Request", service.GetStringRequest());
    Set("Response", service.GetStringResponse());
    
    if(!service.IsSuccessResponse()) {
        throw new Exception(service.GetErrorResponse());
    }
} catch (Exception e) {
    Set("Message", e.Message);
}

return true;
